INSERT INTO `offres` (`id`, `titre`, `description`, `competences`, `date_debut`, `date_fin`, `statut`, `cree_par`, `cree_le`) VALUES
(1, 'genie mecanique offer', '**Ingénieur en Génie Mécanique**\n\n**Résumé :**\nNous recherchons un ingénieur en génie mécanique talentueux pour rejoindre notre équipe d\'experts. Ce poste offre l\'opportunité de travailler sur des projets innovants et de contribuer à l\'amélioration de nos processus. Vous aurez la chance de mettre en pratique vos compétences techniques et votre créativité pour résoudre des problèmes complexes.\n\n**Missions :**\n- Conception et développement de systèmes mécaniques innovants\n- Analyse et optimisation des performances des systèmes existants\n- Gestion de projets d\'ingénierie de A à Z\n- Collaboration avec les équipes de production et de maintenance pour assurer une mise en œuvre efficace\n- Élaboration de rapports techniques et de présentations pour les parties prenantes\n\n**Profil recherché :**\nNous recherchons un candidat avec une formation en génie mécanique, possédant une solide expérience dans la conception et le développement de systèmes mécaniques. La capacité à travailler en équipe, une excellente communication et des compétences analytiques sont essentielles pour réussir dans ce rôle. Une expérience dans l\'industrie manufacturière ou similaire serait un atout.', '[\"solidworks\"]', '2026-05-08', '2026-05-08', 'ouverte', 2, '2026-05-08 17:01:00');

