(22, 6, 'qcm', 'Quel est le but de la commande SQL SELECT ?', '[\"A) Ins\\u00e9rer des donn\\u00e9es dans une table\", \"B) Mettre \\u00e0 jour des donn\\u00e9es dans une table\", \"C) S\\u00e9lectionner des donn\\u00e9es dans une table\", \"D) Supprimer des donn\\u00e9es dans une table\"]', 'C) Sélectionner des données dans une table', 0),
(23, 6, 'qcm', 'Quelle est la fonction de la commande SQL DISTINCT ?', '[\"A) S\\u00e9lectionner des donn\\u00e9es en double\", \"B) S\\u00e9lectionner des donn\\u00e9es uniques\", \"C) Mettre \\u00e0 jour des donn\\u00e9es\", \"D) Supprimer des donn\\u00e9es\"]', 'B) Sélectionner des données uniques', 1),
(24, 6, 'qcm', 'Quel est l\'utilité de l\'alias (AS) en SQL ?', '[\"A) Pour donner un nom \\u00e0 une table\", \"B) Pour donner un nom \\u00e0 une colonne\", \"C) Pour donner un nom \\u00e0 une requ\\u00eate\", \"D) Pour donner un nom \\u00e0 une base de donn\\u00e9es\"]', 'B) Pour donner un nom à une colonne', 2),
(25, 6, 'qcm', 'Quelle est la fonction de la commande SQL WHERE ?', '[\"A) Pour s\\u00e9lectionner des donn\\u00e9es en fonction d\'une condition\", \"B) Pour mettre \\u00e0 jour des donn\\u00e9es\", \"C) Pour supprimer des donn\\u00e9es\", \"D) Pour ins\\u00e9rer des donn\\u00e9es\"]', 'A) Pour sélectionner des données en fonction d\'une condition', 3),
(26, 6, 'qcm', 'Quelle est la différence entre les opérateurs SQL AND et OR ?', '[\"A) AND est utilis\\u00e9 pour s\\u00e9lectionner des donn\\u00e9es en fonction de plusieurs conditions, OR est utilis\\u00e9 pour s\\u00e9lectionner des donn\\u00e9es en fonction d\'au moins une condition\", \"B) AND est utilis\\u00e9 pour s\\u00e9lectionner des donn\\u00e9es en fonction d\'au moins une condition, OR est utilis\\u00e9 pour s\\u00e9lectionner des donn\\u00e9es en fonction de plusieurs conditions\", \"C) AND est utilis\\u00e9 pour mettre \\u00e0 jour des donn\\u00e9es, OR est utilis\\u00e9 pour supprimer des donn\\u00e9es\", \"D) AND est utilis\\u00e9 pour ins\\u00e9rer des donn\\u00e9es, OR est utilis\\u00e9 pour s\\u00e9lectionner des donn\\u00e9es\"]', 'A) AND est utilisé pour sélectionner des données en fonction de plusieurs conditions, OR est utilisé pour sélectionner des données en fonction d\'au moins une condition', 4),
(27, 6, 'qcm', 'Quelle est la fonction de la commande SQL IN ?', '[\"A) Pour s\\u00e9lectionner des donn\\u00e9es en fonction d\'une liste de valeurs\", \"B) Pour mettre \\u00e0 jour des donn\\u00e9es\", \"C) Pour supprimer des donn\\u00e9es\", \"D) Pour ins\\u00e9rer des donn\\u00e9es\"]', 'A) Pour sélectionner des données en fonction d\'une liste de valeurs', 5),
(28, 6, 'qcm', 'Quelle est la fonction de la commande SQL BETWEEN ?', '[\"A) Pour s\\u00e9lectionner des donn\\u00e9es en fonction d\'une plage de valeurs\", \"B) Pour mettre \\u00e0 jour des donn\\u00e9es\", \"C) Pour supprimer des donn\\u00e9es\", \"D) Pour ins\\u00e9rer des donn\\u00e9es\"]', 'A) Pour sélectionner des données en fonction d\'une plage de valeurs', 6),
(29, 6, 'qcm', 'Quelle est la fonction de la commande SQL LIKE ?', '[\"A) Pour s\\u00e9lectionner des donn\\u00e9es en fonction d\'un motif de recherche\", \"B) Pour mettre \\u00e0 jour des donn\\u00e9es\", \"C) Pour supprimer des donn\\u00e9es\", \"D) Pour ins\\u00e9rer des donn\\u00e9es\"]', 'A) Pour sélectionner des données en fonction d\'un motif de recherche', 7),
(30, 6, 'qcm', 'Quelle est la fonction de la commande SQL IS NULL / IS NOT NULL ?', '[\"A) Pour s\\u00e9lectionner des donn\\u00e9es en fonction de la pr\\u00e9sence ou de l\'absence de valeurs\", \"B) Pour mettre \\u00e0 jour des donn\\u00e9es\", \"C) Pour supprimer des donn\\u00e9es\", \"D) Pour ins\\u00e9rer des donn\\u00e9es\"]', 'A) Pour sélectionner des données en fonction de la présence ou de l\'absence de valeurs', 8),
(31, 6, 'qcm', 'Quelle est la fonction de la commande SQL GROUP BY ?', '[\"A) Pour regrouper des donn\\u00e9es en fonction d\'une ou plusieurs colonnes\", \"B) Pour mettre \\u00e0 jour des donn\\u00e9es\", \"C) Pour supprimer des donn\\u00e9es\", \"D) Pour ins\\u00e9rer des donn\\u00e9es\"]', 'A) Pour regrouper des données en fonction d\'une ou plusieurs colonnes', 9),
(32, 6, 'qcm', 'Quelle est la fonction de la commande SQL HAVING ?', '[\"A) Pour s\\u00e9lectionner des donn\\u00e9es en fonction d\'une condition apr\\u00e8s regroupement\", \"B) Pour mettre \\u00e0 jour des donn\\u00e9es\", \"C) Pour supprimer des donn\\u00e9es\", \"D) Pour ins\\u00e9rer des donn\\u00e9es\"]', 'A) Pour sélectionner des données en fonction d\'une condition après regroupement', 10),
(33, 6, 'qcm', 'Quelle est la fonction de la commande SQL ORDER BY ?', '[\"A) Pour trier des donn\\u00e9es en fonction d\'une ou plusieurs colonnes\", \"B) Pour mettre \\u00e0 jour des donn\\u00e9es\", \"C) Pour supprimer des donn\\u00e9es\", \"D) Pour ins\\u00e9rer des donn\\u00e9es\"]', 'A) Pour trier des données en fonction d\'une ou plusieurs colonnes', 11),
(34, 6, 'ouverte', 'Qu\'est-ce que le langage SQL et à quoi sert-il ?', 'null', 'Le langage SQL (Structured Query Language) est un langage de requête utilisé pour gérer et manipuler des données dans des bases de données relationnelles.', 12),
(35, 6, 'ouverte', 'Quelles sont les différentes parties d\'une requête SQL ?', 'null', 'Les différentes parties d\'une requête SQL sont : SELECT, FROM, WHERE, GROUP BY, HAVING, ORDER BY, LIMIT.', 13),
(36, 6, 'ouverte', 'Qu\'est-ce qu\'une base de données relationnelle ?', 'null', 'Une base de données relationnelle est un type de base de données qui stocke des données sous forme de tables avec des lignes et des colonnes, où chaque ligne représente un enregistrement et chaque colonne représente un champ.', 14),
(37, 6, 'ouverte', 'Qu\'est-ce qu\'un index en base de données ?', 'null', 'Un index en base de données est une structure de données qui permet d\'accélérer les requêtes en fournissant un moyen rapide d\'accéder aux données.', 15),
(38, 6, 'ouverte', 'Quelles sont les différentes types de jointures en SQL ?', 'null', 'Les différentes types de jointures en SQL sont : INNER JOIN, LEFT JOIN, RIGHT JOIN, FULL OUTER JOIN.', 16),
(39, 6, 'ouverte', 'Qu\'est-ce qu\'une sous-requête en SQL ?', 'null', 'Une sous-requête en SQL est une requête imbriquée dans une autre requête, qui permet de récupérer des données en fonction d\'une condition.', 17),
(40, 6, 'ouverte', 'Qu\'est-ce qu\'une fonction de regroupement en SQL ?', 'null', 'Une fonction de regroupement en SQL est une fonction qui permet de regrouper des données en fonction d\'une ou plusieurs colonnes, telles que SUM, COUNT, AVG, MAX, MIN.', 18),
(41, 6, 'ouverte', 'Qu\'est-ce qu\'une requête SQL complexe ?', 'null', 'Une requête SQL complexe est une requête qui combine plusieurs opérations, telles que des jointures, des sous-requêtes, des fonctions de regroupement, pour récupérer des données spécifiques.', 19),
(42, 6, 'ouverte', 'Quelles sont les meilleures pratiques pour optimiser les performances d\'une base de données ?', 'null', 'Les meilleures pratiques pour optimiser les performances d\'une base de données incluent l\'utilisation d\'index, la mise à jour régulière des statistiques, l\'optimisation des requêtes, la gestion des ressources système, la mise en place d\'une stratégie de sauvegarde et de récupération.', 20);

